const post = $('Webhook Trigger').first().json.body;
const templateB64 = $input.first().json.content;
let html = Buffer.from(templateB64, 'base64').toString('utf8');

const months=['يناير','فبراير','مارس','أبريل','مايو','يونيو','يوليو','أغسطس','سبتمبر','أكتوبر','نوفمبر','ديسمبر'];
const d = new Date(post.date || new Date());
const tags = Array.isArray(post.tags) ? post.tags : (post.tags||'').split(',').map(t=>t.trim()).filter(Boolean);
const slug = post.slug || (post.title_en||'').toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'');
const postUrl = `https://techservjo.com/blog/posts/${slug}.html`;

const r = {
  SLUG: slug,
  LANG: 'ar', DIR: 'rtl',
  TITLE_AR: post.title_ar||'',
  TITLE_EN: post.title_en||'',
  EXCERPT_AR: post.excerpt_ar||'',
  EXCERPT_EN: post.excerpt_en||'',
  CONTENT_AR: post.content_ar||'',
  CONTENT_EN: post.content_en||'',
  DATE: post.date || d.toISOString().split('T')[0],
  DATE_FORMATTED_AR: `${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`,
  DATE_FORMATTED_EN: d.toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'}),
  IMAGE_URL: post.image_url||'https://images.unsplash.com/photo-1677442136019-21780ecad995?auto=format&fit=crop&q=80&w=800',
  AUTHOR: post.author||'TechServJo Team',
  CATEGORY: post.category||'general',
  CATEGORY_AR: post.category_ar||'عام',
  CATEGORY_EN: post.category_en||'General',
  READ_TIME_AR: String(post.read_time||5),
  READ_TIME_EN: String(post.read_time||5),
  TAGS: tags.join(', '),
  TAGS_HTML: tags.map(t=>`<a href="/blog/?search=${encodeURIComponent(t)}">${t}</a>`).join('\n'),
  WHATSAPP_TEXT: encodeURIComponent(`${post.title_ar} - ${postUrl}`)
};

for (const [k,v] of Object.entries(r)) html = html.replaceAll(`{{${k}}}`, v);

const postEntry = {
  slug, title:{ar:post.title_ar,en:post.title_en},
  excerpt:{ar:post.excerpt_ar,en:post.excerpt_en},
  date: r.DATE, author: r.AUTHOR,
  category: r.CATEGORY, tags,
  image: post.image_url||'', lang:['ar','en'],
  readTime:{ar:post.read_time||5,en:post.read_time||5}
};

return [{json:{slug, html, postEntry, postUrl, chatId: post.chatId||null}}];

const sha = $input.first().json.sha;
const index = JSON.parse(Buffer.from($input.first().json.content,'base64').toString('utf8'));
const newPost = $('Code: Build HTML from Template').first().json.postEntry;
const slug = $('Code: Build HTML from Template').first().json.slug;
const postUrl = $('Code: Build HTML from Template').first().json.postUrl;
const chatId = $('Code: Build HTML from Template').first().json.chatId;
index.posts.unshift(newPost);
const updatedStr = JSON.stringify(index, null, 2);
return [{json:{sha, updatedStr, slug, postUrl, chatId, title_ar: newPost.title.ar, title_en: newPost.title.en}}];
